import React from "react"
import { useStaticQuery, graphql } from "gatsby"
import Img from "gatsby-image"
import data from "../../../data/data"
import { Wrap, Eyebrow, ButtonA } from "../../common"
import { Decode, Reveal } from "../../fx"
import ShellScene from "../../three/shellScene"
import CubeScene from "../../three/cubeScene"
import {
  HeroSection,
  HeroCopy,
  HeroName,
  Redaction,
  CtaRow,
  PortraitZone,
  ScanPortrait,
  Mrz,
} from "./style"

const MRZ_BASE_DELAY = 1000

/* fragment scrolling dies inside the smoother's fixed wrapper — write
   the native scroll position instead; the smoother glides to it */
const scrollToWorks = e => {
  e.preventDefault()
  const el = document.querySelector("#selected-work")
  if (!el) return
  const y =
    el.getBoundingClientRect().top +
    (window.__SMOOTH_Y != null ? window.__SMOOTH_Y : window.pageYOffset)
  window.scrollTo(0, Math.round(y))
}

const Hero = () => {
  const { portrait } = useStaticQuery(graphql`
    query {
      portrait: file(relativePath: { eq: "header-me.png" }) {
        childImageSharp {
          fluid(maxWidth: 900, quality: 90) {
            ...GatsbyImageSharpFluid
          }
        }
      }
    }
  `)

  const readouts = [
    ["SUBJECT", data.SiteAuthor.toUpperCase()],
    ["ROLE", data.SiteRole.toUpperCase()],
    [
      "BASE",
      `${
        data.SiteDossier.coordinates
      } — ${data.SiteDossier.base.toUpperCase()}`,
    ],
    ["STACK", data.SiteDossier.stack.toUpperCase()],
  ]

  return (
    <Wrap>
      <HeroSection>
        <CubeScene className="cube" />

        <HeroCopy>
          <Reveal delay={150}>
            <Eyebrow jp={data.SiteRoleJa}>{data.SiteRole}</Eyebrow>
          </Reveal>
          <HeroName>
            <span className="l1">
              <Decode text="PEBRIAN" delay={300} duration={800} />
            </span>
            <span className="l2">
              <Decode text="CHARLIADY" delay={520} duration={800} />
            </span>
          </HeroName>
          <Reveal delay={550}>
            <Redaction>
              <span className="bar bar-1" aria-hidden="true" />
              <span className="bar bar-2" aria-hidden="true" />
              <span className="note">
                This section intentionally left blank
              </span>
            </Redaction>
          </Reveal>
          <Reveal delay={750}>
            <CtaRow>
              <ButtonA href="#selected-work" onClick={scrollToWorks}>
                View selected work
              </ButtonA>
              <ButtonA href={`mailto:${data.SiteContact.email}`}>
                Make contact
              </ButtonA>
            </CtaRow>
          </Reveal>
        </HeroCopy>

        <PortraitZone>
          <Reveal delay={400}>
            <ScanPortrait data-shell-anchor="portrait">
              <ShellScene className="orbit" media="(max-width: 850px)" />
              <figure className="portrait">
                <span className="bk bk-tl" aria-hidden="true" />
                <span className="bk bk-tr" aria-hidden="true" />
                <span className="bk bk-bl" aria-hidden="true" />
                <span className="bk bk-br" aria-hidden="true" />
                {portrait && (
                  <Img
                    fluid={portrait.childImageSharp.fluid}
                    alt={`Portrait of ${data.SiteAuthor}`}
                  />
                )}
                <span className="scan" aria-hidden="true" />
                <span className="subject-id" aria-hidden="true">
                  <span>FIG. 00 — SHELL</span>
                  <span className="id-code">
                    {data.SiteDossier.coordinates}
                  </span>
                </span>
              </figure>
            </ScanPortrait>
          </Reveal>
        </PortraitZone>

        <Reveal delay={900}>
          <Mrz>
            {readouts.map(([label, value], i) => (
              <div key={label}>
                <dt>{label}</dt>
                <dd>
                  <Decode
                    text={value}
                    delay={MRZ_BASE_DELAY + i * 140}
                    duration={500}
                  />
                </dd>
              </div>
            ))}
            <div className="status">
              <dt>STATUS</dt>
              <dd>
                <span className="dot" aria-hidden="true" />
                <Decode
                  text={data.SiteDossier.status.toUpperCase()}
                  delay={MRZ_BASE_DELAY + readouts.length * 140}
                  duration={500}
                />
              </dd>
            </div>
          </Mrz>
        </Reveal>
      </HeroSection>
    </Wrap>
  )
}

export default Hero
